package com.weeklycommit.ai.controller;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.dto.AiFeedbackRequest;
import com.weeklycommit.ai.dto.StructuredEvidenceResponse;
import com.weeklycommit.ai.dto.WhatIfRequest;
import com.weeklycommit.ai.dto.WhatIfResponse;
import com.weeklycommit.ai.evidence.StructuredEvidence;
import com.weeklycommit.ai.evidence.StructuredEvidenceService;
import com.weeklycommit.ai.dto.CommitDraftAssistRequest;
import com.weeklycommit.ai.dto.CommitDraftAssistResponse;
import com.weeklycommit.ai.dto.CommitLintRequest;
import com.weeklycommit.ai.dto.CommitLintResponse;
import com.weeklycommit.ai.dto.InsightCardDto;
import com.weeklycommit.ai.dto.InsightListResponse;
import com.weeklycommit.ai.dto.ManagerAiSummaryResponse;
import com.weeklycommit.ai.dto.RagQueryRequest;
import com.weeklycommit.ai.dto.RagQueryResponse;
import com.weeklycommit.ai.dto.RagSourceDto;
import com.weeklycommit.ai.dto.RcdoSuggestRequest;
import com.weeklycommit.ai.dto.RcdoSuggestResponse;
import com.weeklycommit.ai.dto.ReconcileAssistRequest;
import com.weeklycommit.ai.dto.ReconcileAssistResponse;
import com.weeklycommit.ai.dto.RiskSignalResponse.PlanRiskSignals;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProvider;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.rag.SemanticIndexService;
import com.weeklycommit.ai.rag.SemanticQueryService;
import com.weeklycommit.ai.service.AiSuggestionService;
import com.weeklycommit.ai.service.CommitDraftAssistService;
import com.weeklycommit.ai.service.CommitLintService;
import com.weeklycommit.ai.service.ManagerAiSummaryService;
import com.weeklycommit.ai.service.RcdoSuggestService;
import com.weeklycommit.ai.service.RiskDetectionService;
import com.weeklycommit.ai.service.ReconcileAssistService;
import com.weeklycommit.ai.service.WhatIfService;
import com.weeklycommit.domain.entity.AiSuggestion;
import com.weeklycommit.domain.repository.AiSuggestionRepository;
import jakarta.validation.Valid;
import java.time.LocalDate;
import java.util.ArrayList;
import java.util.List;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.format.annotation.DateTimeFormat;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestHeader;
import org.springframework.web.bind.annotation.RestController;

/**
 * REST endpoints for AI-powered commit assistance, linting, RCDO suggestions,
 * risk detection, reconciliation assistance, manager summaries, RAG queries,
 * and proactive insight retrieval.
 *
 * <p>
 * All endpoints degrade gracefully: when AI is disabled or unavailable the
 * response includes {@code aiAvailable: false} and no error is returned. Core
 * workflow is never blocked by AI unavailability.
 */
@RestController
public class AiController {

	private static final Logger log = LoggerFactory.getLogger(AiController.class);

	private final CommitDraftAssistService draftAssistService;
	private final CommitLintService lintService;
	private final RcdoSuggestService rcdoSuggestService;
	private final RiskDetectionService riskDetectionService;
	private final ReconcileAssistService reconcileAssistService;
	private final ManagerAiSummaryService managerSummaryService;
	private final AiSuggestionService suggestionService;
	private final AiProviderRegistry providerRegistry;
	private final SemanticIndexService semanticIndexService;
	private final SemanticQueryService semanticQueryService;
	private final AiSuggestionRepository suggestionRepo;
	private final StructuredEvidenceService evidenceService;
	private final WhatIfService whatIfService;
	private final ObjectMapper objectMapper;

	public AiController(CommitDraftAssistService draftAssistService, CommitLintService lintService,
			RcdoSuggestService rcdoSuggestService, RiskDetectionService riskDetectionService,
			ReconcileAssistService reconcileAssistService, ManagerAiSummaryService managerSummaryService,
			AiSuggestionService suggestionService, AiProviderRegistry providerRegistry,
			SemanticIndexService semanticIndexService, SemanticQueryService semanticQueryService,
			AiSuggestionRepository suggestionRepo, StructuredEvidenceService evidenceService,
			WhatIfService whatIfService, ObjectMapper objectMapper) {
		this.draftAssistService = draftAssistService;
		this.lintService = lintService;
		this.rcdoSuggestService = rcdoSuggestService;
		this.riskDetectionService = riskDetectionService;
		this.reconcileAssistService = reconcileAssistService;
		this.managerSummaryService = managerSummaryService;
		this.suggestionService = suggestionService;
		this.providerRegistry = providerRegistry;
		this.semanticIndexService = semanticIndexService;
		this.semanticQueryService = semanticQueryService;
		this.suggestionRepo = suggestionRepo;
		this.evidenceService = evidenceService;
		this.whatIfService = whatIfService;
		this.objectMapper = objectMapper;
	}

	// -------------------------------------------------------------------------
	// Capability 1: Commit draft assistance
	// -------------------------------------------------------------------------

	/**
	 * Returns suggestions for improving a commit draft (title, description, success
	 * criteria, estimate). Suggestions are editable proposals — never auto-applied.
	 */
	@PostMapping("/api/ai/commit-draft-assist")
	public ResponseEntity<CommitDraftAssistResponse> commitDraftAssist(
			@Valid @RequestBody CommitDraftAssistRequest request) {
		return ResponseEntity.ok(draftAssistService.assist(request));
	}

	// -------------------------------------------------------------------------
	// Capability 2: Commit quality lint
	// -------------------------------------------------------------------------

	/**
	 * Runs commit quality lint for a plan. Returns {@code hardValidation} (blocks
	 * lock) and {@code softGuidance} (informational) messages.
	 */
	@PostMapping("/api/ai/commit-lint")
	public ResponseEntity<CommitLintResponse> commitLint(@Valid @RequestBody CommitLintRequest request) {
		return ResponseEntity.ok(lintService.lint(request));
	}

	// -------------------------------------------------------------------------
	// Capability 3: RCDO link suggestion
	// -------------------------------------------------------------------------

	/**
	 * Suggests a primary RCDO node for a commit draft. Only surfaced when
	 * confidence &ge; 0.7. Never auto-links.
	 */
	@PostMapping("/api/ai/rcdo-suggest")
	public ResponseEntity<RcdoSuggestResponse> rcdoSuggest(@Valid @RequestBody RcdoSuggestRequest request) {
		return ResponseEntity.ok(rcdoSuggestService.suggest(request));
	}

	// -------------------------------------------------------------------------
	// Capability 4: Risk signals
	// -------------------------------------------------------------------------

	/**
	 * Returns current risk signals for the given plan. Hidden from peers — only the
	 * plan owner and their manager should call this endpoint.
	 */
	@GetMapping("/api/plans/{id}/risk-signals")
	public ResponseEntity<PlanRiskSignals> getRiskSignals(@PathVariable UUID id,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID callerId) {
		if (callerId == null) {
			return ResponseEntity.badRequest().build();
		}
		return ResponseEntity.ok(riskDetectionService.getRiskSignals(id, callerId));
	}

	// -------------------------------------------------------------------------
	// Capability 5: Reconciliation assistance
	// -------------------------------------------------------------------------

	/**
	 * Returns reconciliation assistance: likely outcomes, draft summary, and
	 * carry-forward recommendations for a plan entering the reconcile phase.
	 */
	@PostMapping("/api/ai/reconcile-assist")
	public ResponseEntity<ReconcileAssistResponse> reconcileAssist(@Valid @RequestBody ReconcileAssistRequest request) {
		return ResponseEntity.ok(reconcileAssistService.assist(request));
	}

	// -------------------------------------------------------------------------
	// Capability 5b: What-If plan simulation
	// -------------------------------------------------------------------------

	/**
	 * Simulates hypothetical plan mutations (add/remove/modify commits) in-memory
	 * and returns a structured impact analysis with optional LLM narrative.
	 *
	 * <p>
	 * No data is persisted. The response always includes the structured
	 * before/after analysis; {@code narrative} and {@code recommendation} are null
	 * when AI is disabled or unavailable.
	 */
	@PostMapping("/api/ai/what-if")
	public ResponseEntity<WhatIfResponse> whatIf(@Valid @RequestBody WhatIfRequest request) {
		return ResponseEntity.ok(whatIfService.simulate(request));
	}

	// -------------------------------------------------------------------------
	// Capability 6: Manager team AI summary
	// -------------------------------------------------------------------------

	/**
	 * Returns the AI-generated team summary for the given week. Only accessible to
	 * managers.
	 */
	@GetMapping("/api/teams/{id}/week/{weekStart}/ai-summary")
	public ResponseEntity<ManagerAiSummaryResponse> getTeamAiSummary(@PathVariable UUID id,
			@PathVariable @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate weekStart,
			@RequestHeader(value = "X-Actor-User-Id", required = false) UUID callerId) {
		return ResponseEntity.ok(managerSummaryService.getSummary(id, weekStart, callerId));
	}

	// -------------------------------------------------------------------------
	// Capability 7: RAG query
	// -------------------------------------------------------------------------

	/**
	 * Executes a semantic (RAG) query against the team's indexed planning history.
	 * Returns an AI-generated answer with source citations.
	 *
	 * <p>
	 * Degrades gracefully: returns {@code {aiAvailable: false}} when Pinecone or
	 * the LLM is unavailable.
	 */
	@PostMapping("/api/ai/query")
	public ResponseEntity<RagQueryResponse> ragQuery(@Valid @RequestBody RagQueryRequest request) {
		try {
			SemanticQueryService.RagQueryResult result = semanticQueryService.query(request.question(),
					request.teamId(), request.userId());
			if (!result.available()) {
				return ResponseEntity.ok(RagQueryResponse.unavailable());
			}
			List<RagSourceDto> sources = result.sources().stream()
					.map(s -> new RagSourceDto(s.entityType(), s.entityId(), s.weekStartDate(), s.snippet())).toList();
			return ResponseEntity.ok(
					new RagQueryResponse(true, result.answer(), sources, result.confidence(), result.suggestionId()));
		} catch (Exception ex) {
			log.warn("RAG query failed: {}", ex.getMessage());
			return ResponseEntity.ok(RagQueryResponse.unavailable());
		}
	}

	// -------------------------------------------------------------------------
	// Capability 8: Team AI insights
	// -------------------------------------------------------------------------

	/**
	 * Returns persisted TEAM_INSIGHT rows for the given team and week.
	 *
	 * <p>
	 * Insights are generated by the scheduled job in
	 * {@link com.weeklycommit.ai.rag.InsightGenerationService}. This endpoint reads
	 * them back from the {@code ai_suggestion} table.
	 */
	@GetMapping("/api/teams/{id}/week/{weekStart}/ai-insights")
	public ResponseEntity<InsightListResponse> getTeamInsights(@PathVariable UUID id,
			@PathVariable @DateTimeFormat(iso = DateTimeFormat.ISO.DATE) LocalDate weekStart) {
		try {
			List<AiSuggestion> rows = suggestionRepo.findByTeamIdAndWeekStartDateAndSuggestionType(id, weekStart,
					AiContext.TYPE_TEAM_INSIGHT);
			List<InsightCardDto> insights = parseInsightCards(rows);
			return ResponseEntity.ok(new InsightListResponse(true, insights));
		} catch (Exception ex) {
			log.warn("Failed to retrieve team insights for team={}, week={}: {}", id, weekStart, ex.getMessage());
			return ResponseEntity.ok(InsightListResponse.unavailable());
		}
	}

	// -------------------------------------------------------------------------
	// Capability 9: Personal (plan) AI insights
	// -------------------------------------------------------------------------

	/**
	 * Returns persisted PERSONAL_INSIGHT rows for the given plan.
	 *
	 * <p>
	 * Insights are generated on plan lock (via
	 * {@link com.weeklycommit.ai.rag.InsightGenerationService#generatePersonalInsightsAsync})
	 * and by the daily sweep.
	 */
	@GetMapping("/api/plans/{id}/ai-insights")
	public ResponseEntity<InsightListResponse> getPlanInsights(@PathVariable UUID id) {
		try {
			List<AiSuggestion> rows = suggestionRepo.findByPlanIdAndSuggestionType(id, AiContext.TYPE_PERSONAL_INSIGHT);
			List<InsightCardDto> insights = parseInsightCards(rows);
			return ResponseEntity.ok(new InsightListResponse(true, insights));
		} catch (Exception ex) {
			log.warn("Failed to retrieve personal insights for plan={}: {}", id, ex.getMessage());
			return ResponseEntity.ok(InsightListResponse.unavailable());
		}
	}

	// -------------------------------------------------------------------------
	// Admin: full reindex
	// -------------------------------------------------------------------------

	/**
	 * Triggers an async full reindex of all plans into Pinecone. Returns
	 * immediately; indexing runs in a background thread. Intended for dev/admin use
	 * after bulk SQL seed or Pinecone wipes.
	 */
	@PostMapping("/api/admin/ai/reindex")
	public ResponseEntity<java.util.Map<String, Object>> triggerFullReindex() {
		log.info("Admin full reindex triggered");
		int count = semanticIndexService.fullReindex();
		java.util.LinkedHashMap<String, Object> result = new java.util.LinkedHashMap<>();
		result.put("plansQueued", count);
		result.put("status", count > 0 ? "indexing_started" : "pinecone_unavailable");
		result.put("message",
				count > 0
						? "Indexing " + count + " plans in background. Check server logs for completion."
						: "Pinecone not configured.");
		return ResponseEntity.ok(result);
	}

	// -------------------------------------------------------------------------
	// Structured Evidence
	// -------------------------------------------------------------------------

	/**
	 * Returns a structured evidence bundle for a plan — SQL facts, carry-forward
	 * lineage, semantic matches, and risk features. Used by the frontend evidence
	 * drawer to show exactly what the AI used to produce its answers.
	 */
	@GetMapping("/api/plans/{planId}/evidence")
	public ResponseEntity<StructuredEvidenceResponse> getEvidence(@PathVariable UUID planId,
			@org.springframework.web.bind.annotation.RequestParam(required = false) String question) {
		try {
			StructuredEvidence evidence = evidenceService.gatherForPlan(planId, question);
			return ResponseEntity.ok(StructuredEvidenceResponse.of(evidence));
		} catch (Exception e) {
			log.warn("Evidence gathering failed for plan {}: {}", planId, e.getMessage());
			return ResponseEntity.ok(StructuredEvidenceResponse.unavailable());
		}
	}

	/**
	 * Returns a structured evidence bundle for a specific commit — includes
	 * carry-forward lineage tracing.
	 */
	@GetMapping("/api/commits/{commitId}/evidence")
	public ResponseEntity<StructuredEvidenceResponse> getCommitEvidence(@PathVariable UUID commitId,
			@org.springframework.web.bind.annotation.RequestParam(required = false) String question) {
		try {
			StructuredEvidence evidence = evidenceService.gatherForCommit(commitId, question);
			return ResponseEntity.ok(StructuredEvidenceResponse.of(evidence));
		} catch (Exception e) {
			log.warn("Evidence gathering failed for commit {}: {}", commitId, e.getMessage());
			return ResponseEntity.ok(StructuredEvidenceResponse.unavailable());
		}
	}

	// -------------------------------------------------------------------------
	// AI Status
	// -------------------------------------------------------------------------

	/**
	 * Returns the current AI provider status: enabled, provider name/version,
	 * availability. Useful for ops dashboards and frontend feature checks.
	 */
	@GetMapping("/api/ai/status")
	public ResponseEntity<java.util.Map<String, Object>> getAiStatus() {
		java.util.Optional<AiProvider> active = providerRegistry.getActiveProvider();
		java.util.Map<String, Object> status = new java.util.LinkedHashMap<>();
		status.put("aiEnabled", providerRegistry.isAiEnabled());
		status.put("providerName", active.map(AiProvider::getName).orElse("none"));
		status.put("providerVersion", active.map(AiProvider::getVersion).orElse("none"));
		status.put("available", active.map(AiProvider::isAvailable).orElse(false));
		return ResponseEntity.ok(status);
	}

	// -------------------------------------------------------------------------
	// Feedback
	// -------------------------------------------------------------------------

	/**
	 * Records user feedback (ACCEPTED / DISMISSED / EDITED) on an AI suggestion.
	 */
	@PostMapping("/api/ai/feedback")
	public ResponseEntity<Void> recordFeedback(@Valid @RequestBody AiFeedbackRequest request) {
		suggestionService.recordFeedback(request);
		return ResponseEntity.status(HttpStatus.CREATED).build();
	}

	// -------------------------------------------------------------------------
	// Private helpers
	// -------------------------------------------------------------------------

	/**
	 * Parses each {@link AiSuggestion}'s {@code suggestionPayload} JSON into an
	 * {@link InsightCardDto}. Rows whose payload cannot be parsed are silently
	 * skipped.
	 */
	private List<InsightCardDto> parseInsightCards(List<AiSuggestion> rows) {
		List<InsightCardDto> result = new ArrayList<>(rows.size());
		for (AiSuggestion row : rows) {
			try {
				JsonNode root = objectMapper.readTree(row.getSuggestionPayload());
				String insightText = root.path("insightText").asText(row.getRationale());
				String severity = root.path("severity").asText("LOW");
				String actionSuggestion = root.path("actionSuggestion").asText("");
				List<String> sourceEntityIds = new ArrayList<>();
				JsonNode idsNode = root.path("sourceEntityIds");
				if (idsNode.isArray()) {
					for (JsonNode n : idsNode) {
						sourceEntityIds.add(n.asText());
					}
				}
				String createdAt = row.getCreatedAt() != null ? row.getCreatedAt().toString() : "";
				result.add(new InsightCardDto(row.getId(), insightText, severity, sourceEntityIds, actionSuggestion,
						createdAt));
			} catch (Exception ex) {
				log.debug("Skipping unparseable insight payload for suggestion {}: {}", row.getId(), ex.getMessage());
			}
		}
		return result;
	}
}

package com.weeklycommit.ai.provider;

import java.util.List;
import java.util.Map;
import java.util.UUID;

/**
 * Input context supplied to an {@link AiProvider} when requesting a suggestion.
 * All fields are optional except {@code suggestionType}.
 */
public record AiContext(
		/** Discriminator for the kind of suggestion being requested. */
		String suggestionType,
		/** Requesting user (for personalisation and audit). */
		UUID userId,
		/** Plan being analysed, if applicable. */
		UUID planId,
		/** Specific commit being analysed, if applicable. */
		UUID commitId,
		/** Serialised current commit fields (title, chessPiece, etc.). */
		Map<String, Object> commitData,
		/** Serialised plan summary (state, capacity, etc.). */
		Map<String, Object> planData,
		/** Recent historical commits for pattern matching. */
		List<Map<String, Object>> historicalCommits,
		/** Relevant RCDO tree nodes. */
		List<Map<String, Object>> rcdoTree,
		/** Free-form additional context (e.g., scope changes, risk inputs). */
		Map<String, Object> additionalContext) {

	/** Suggestion type constant — commit draft assistance. */
	public static final String TYPE_COMMIT_DRAFT = "COMMIT_DRAFT_ASSIST";

	/** Suggestion type constant — commit quality lint. */
	public static final String TYPE_COMMIT_LINT = "COMMIT_LINT";

	/** Suggestion type constant — RCDO link suggestion. */
	public static final String TYPE_RCDO_SUGGEST = "RCDO_SUGGEST";

	/** Suggestion type constant — risk signal detection. */
	public static final String TYPE_RISK_SIGNAL = "RISK_SIGNAL";

	/** Suggestion type constant — reconciliation assistance. */
	public static final String TYPE_RECONCILE_ASSIST = "RECONCILE_ASSIST";

	/** Suggestion type constant — team manager AI summary. */
	public static final String TYPE_TEAM_SUMMARY = "TEAM_SUMMARY";

	/** Suggestion type constant — RAG intent classification. */
	public static final String TYPE_RAG_INTENT = "RAG_INTENT";

	/** Suggestion type constant — RAG answer generation. */
	public static final String TYPE_RAG_QUERY = "RAG_QUERY";

	/** Suggestion type constant — proactive team-level insight. */
	public static final String TYPE_TEAM_INSIGHT = "TEAM_INSIGHT";

	/** Suggestion type constant — proactive personal/plan-level insight. */
	public static final String TYPE_PERSONAL_INSIGHT = "PERSONAL_INSIGHT";

	/** Suggestion type constant — what-if plan simulation narration. */
	public static final String TYPE_WHAT_IF = "WHAT_IF";
}

package com.weeklycommit.ai.provider;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.node.ArrayNode;
import com.fasterxml.jackson.databind.node.ObjectNode;
import java.io.IOException;
import java.net.URI;
import java.net.http.HttpClient;
import java.net.http.HttpRequest;
import java.net.http.HttpResponse;
import java.time.Duration;
import java.time.Instant;
import java.util.Map;
import java.util.concurrent.atomic.AtomicLong;
import java.util.concurrent.atomic.AtomicReference;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.boot.autoconfigure.condition.ConditionalOnProperty;
import org.springframework.core.io.ClassPathResource;
import org.springframework.stereotype.Component;

/**
 * Production AI provider that routes requests through OpenRouter.
 *
 * <p>
 * Activated when {@code ai.provider=openrouter} (the default). Falls back to
 * unavailable when the API key is blank or the service is unreachable.
 *
 * <p>
 * Features:
 * <ul>
 * <li>Per-suggestion-type prompt templates loaded from classpath</li>
 * <li>Cached health check (60 s TTL) to avoid hammering the API</li>
 * <li>Simple rate limiting via token-bucket (10 req/min default)</li>
 * <li>Token counting from response headers for cost tracking</li>
 * </ul>
 */
@Component
@ConditionalOnProperty(name = "ai.provider", havingValue = "openrouter", matchIfMissing = true)
public class OpenRouterAiProvider implements AiProvider {

	private static final Logger log = LoggerFactory.getLogger(OpenRouterAiProvider.class);

	private final String apiKey;
	private final String model;
	private final int maxTokens;
	private final String baseUrl;
	private final ObjectMapper objectMapper;
	private final HttpClient httpClient;

	/** Cached availability result: [timestamp, available]. */
	private final AtomicReference<Instant> lastHealthCheck = new AtomicReference<>(Instant.EPOCH);
	private volatile boolean lastHealthResult = false;
	private static final Duration HEALTH_CACHE_TTL = Duration.ofSeconds(60);

	/** Simple rate limiter: track request count per minute window. */
	private final AtomicLong windowStart = new AtomicLong(System.currentTimeMillis());
	private final AtomicLong windowCount = new AtomicLong(0);
	private static final int MAX_REQUESTS_PER_MINUTE = 30;

	/** Running totals for observability. */
	private final AtomicLong totalTokensUsed = new AtomicLong(0);
	private final AtomicLong totalRequests = new AtomicLong(0);

	public OpenRouterAiProvider(@Value("${ai.openrouter.api-key:}") String apiKey,
			@Value("${ai.openrouter.model:anthropic/claude-sonnet-4-20250514}") String model,
			@Value("${ai.openrouter.max-tokens:1024}") int maxTokens,
			@Value("${ai.openrouter.base-url:https://openrouter.ai/api/v1}") String baseUrl,
			ObjectMapper objectMapper) {
		this.apiKey = apiKey;
		this.model = model;
		this.maxTokens = maxTokens;
		this.baseUrl = baseUrl;
		this.objectMapper = objectMapper;
		this.httpClient = HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(10)).build();

		if (apiKey == null || apiKey.isBlank()) {
			log.warn("OpenRouter API key is blank — provider will report unavailable");
		} else {
			log.info("OpenRouterAiProvider initialized: model={}, maxTokens={}", model, maxTokens);
		}
	}

	// ── AiProvider contract ──────────────────────────────────────────────

	@Override
	public String getName() {
		return "openrouter";
	}

	@Override
	public String getVersion() {
		return model;
	}

	@Override
	public boolean isAvailable() {
		if (apiKey == null || apiKey.isBlank()) {
			return false;
		}
		// Cached health check
		Instant now = Instant.now();
		if (Duration.between(lastHealthCheck.get(), now).compareTo(HEALTH_CACHE_TTL) < 0) {
			return lastHealthResult;
		}
		// Fresh check — just verify the API key works with a tiny request
		try {
			HttpRequest req = HttpRequest.newBuilder().uri(URI.create(baseUrl + "/models"))
					.header("Authorization", "Bearer " + apiKey).timeout(Duration.ofSeconds(5)).GET().build();
			HttpResponse<String> resp = httpClient.send(req, HttpResponse.BodyHandlers.ofString());
			lastHealthResult = resp.statusCode() == 200;
		} catch (Exception e) {
			log.debug("OpenRouter health check failed: {}", e.getMessage());
			lastHealthResult = false;
		}
		lastHealthCheck.set(now);
		return lastHealthResult;
	}

	@Override
	public AiSuggestionResult generateSuggestion(AiContext context) {
		if (apiKey == null || apiKey.isBlank()) {
			return AiSuggestionResult.unavailable();
		}

		// Rate limiting
		if (!tryAcquireRate()) {
			log.warn("OpenRouter rate limit exceeded for type={}", context.suggestionType());
			return AiSuggestionResult.unavailable();
		}

		try {
			String promptVersion = resolvePromptVersion(context.suggestionType());
			String systemPrompt = loadPromptTemplate(context.suggestionType());
			String userMessage = buildUserMessage(context);

			String responseBody = callOpenRouter(systemPrompt, userMessage);
			totalRequests.incrementAndGet();

			return parseResponse(responseBody, context.suggestionType(), promptVersion);
		} catch (Exception e) {
			log.warn("OpenRouter request failed for type={}: {}", context.suggestionType(), e.getMessage());
			return AiSuggestionResult.unavailable();
		}
	}

	// ── HTTP call ────────────────────────────────────────────────────────

	private String callOpenRouter(String systemPrompt, String userMessage) throws IOException, InterruptedException {
		ObjectNode body = objectMapper.createObjectNode();
		body.put("model", model);
		body.put("max_tokens", maxTokens);

		ArrayNode messages = body.putArray("messages");
		messages.addObject().put("role", "system").put("content", systemPrompt);
		messages.addObject().put("role", "user").put("content", userMessage);

		String json = objectMapper.writeValueAsString(body);

		HttpRequest request = HttpRequest.newBuilder().uri(URI.create(baseUrl + "/chat/completions"))
				.header("Authorization", "Bearer " + apiKey).header("Content-Type", "application/json")
				.header("HTTP-Referer", "https://weeklycommit.dev").header("X-Title", "Weekly Commit")
				.timeout(Duration.ofSeconds(30)).POST(HttpRequest.BodyPublishers.ofString(json)).build();

		HttpResponse<String> response = httpClient.send(request, HttpResponse.BodyHandlers.ofString());

		if (response.statusCode() != 200) {
			throw new IOException("OpenRouter returned " + response.statusCode() + ": " + response.body());
		}

		// Track tokens from response
		try {
			JsonNode respNode = objectMapper.readTree(response.body());
			JsonNode usage = respNode.get("usage");
			if (usage != null && usage.has("total_tokens")) {
				totalTokensUsed.addAndGet(usage.get("total_tokens").asLong());
			}
		} catch (Exception ignored) {
		}

		return response.body();
	}

	// ── Response parsing ─────────────────────────────────────────────────

	private AiSuggestionResult parseResponse(String responseBody, String suggestionType, String promptVersion) {
		try {
			JsonNode root = objectMapper.readTree(responseBody);
			JsonNode choices = root.get("choices");
			if (choices == null || choices.isEmpty()) {
				return AiSuggestionResult.unavailable();
			}

			String content = choices.get(0).path("message").path("content").asText("");
			if (content.isBlank()) {
				return AiSuggestionResult.unavailable();
			}

			// The model should return JSON. Extract it — handle markdown code fences.
			String jsonPayload = extractJson(content);
			String rationale = extractRationale(content, jsonPayload);

			// Validate it's parseable JSON
			objectMapper.readTree(jsonPayload);

			return new AiSuggestionResult(true, jsonPayload, rationale, 0.85, model, promptVersion);
		} catch (Exception e) {
			log.warn("Failed to parse OpenRouter response for {}: {}", suggestionType, e.getMessage());
			return AiSuggestionResult.unavailable();
		}
	}

	// ── Prompt construction ──────────────────────────────────────────────

	private String loadPromptTemplate(String suggestionType) {
		String filename = switch (suggestionType) {
			case AiContext.TYPE_COMMIT_DRAFT -> "commit-draft-assist.txt";
			case AiContext.TYPE_COMMIT_LINT -> "commit-lint.txt";
			case AiContext.TYPE_RCDO_SUGGEST -> "rcdo-suggest.txt";
			case AiContext.TYPE_RISK_SIGNAL -> "risk-signal.txt";
			case AiContext.TYPE_RECONCILE_ASSIST -> "reconcile-assist.txt";
			case AiContext.TYPE_TEAM_SUMMARY -> "team-summary.txt";
			case AiContext.TYPE_RAG_INTENT -> "rag-intent.txt";
			case AiContext.TYPE_RAG_QUERY -> "rag-query.txt";
			case AiContext.TYPE_TEAM_INSIGHT -> "team-insight.txt";
			case AiContext.TYPE_PERSONAL_INSIGHT -> "personal-insight.txt";
			case AiContext.TYPE_WHAT_IF -> "what-if.txt";
			case "FAITHFULNESS_EVAL" -> "faithfulness-eval.txt";
			default -> "generic.txt";
		};
		try {
			ClassPathResource resource = new ClassPathResource("prompts/" + filename);
			return new String(resource.getInputStream().readAllBytes());
		} catch (IOException e) {
			log.debug("Prompt template not found: prompts/{}, using default", filename);
			return "You are a helpful planning assistant for a weekly commitment tool. "
					+ "Respond with valid JSON matching the expected schema.";
		}
	}

	private String buildUserMessage(AiContext context) {
		try {
			Map<String, Object> msg = Map.of("suggestionType", context.suggestionType(), "commitData",
					context.commitData() != null ? context.commitData() : Map.of(), "planData",
					context.planData() != null ? context.planData() : Map.of(), "historicalCommits",
					context.historicalCommits() != null ? context.historicalCommits() : java.util.List.of(), "rcdoTree",
					context.rcdoTree() != null ? context.rcdoTree() : java.util.List.of(), "additionalContext",
					context.additionalContext() != null ? context.additionalContext() : Map.of());
			return objectMapper.writeValueAsString(msg);
		} catch (Exception e) {
			return "{}";
		}
	}

	/**
	 * Resolves the prompt version identifier for the given suggestion type. Uses
	 * the base prompt filename as the version key with a "-v1" suffix. When A/B
	 * testing, this method can be extended to read from feature flags and load
	 * variant templates (e.g. "commit-draft-assist-v2.txt").
	 */
	private String resolvePromptVersion(String suggestionType) {
		String base = switch (suggestionType) {
			case AiContext.TYPE_COMMIT_DRAFT -> "commit-draft-assist";
			case AiContext.TYPE_COMMIT_LINT -> "commit-lint";
			case AiContext.TYPE_RCDO_SUGGEST -> "rcdo-suggest";
			case AiContext.TYPE_RISK_SIGNAL -> "risk-signal";
			case AiContext.TYPE_RECONCILE_ASSIST -> "reconcile-assist";
			case AiContext.TYPE_TEAM_SUMMARY -> "team-summary";
			case AiContext.TYPE_RAG_INTENT -> "rag-intent";
			case AiContext.TYPE_RAG_QUERY -> "rag-query";
			case AiContext.TYPE_TEAM_INSIGHT -> "team-insight";
			case AiContext.TYPE_PERSONAL_INSIGHT -> "personal-insight";
			case AiContext.TYPE_WHAT_IF -> "what-if";
			default -> "generic";
		};
		// commit-draft-assist was updated to v2 (added title length rule + example).
		if ("commit-draft-assist".equals(base)) {
			return base + "-v2";
		}
		return base + "-v1";
	}

	// ── Helpers ──────────────────────────────────────────────────────────

	/**
	 * Extracts JSON from model output, handling ```json fences.
	 */
	private String extractJson(String content) {
		String trimmed = content.trim();
		// Handle ```json ... ``` fences
		if (trimmed.contains("```json")) {
			int start = trimmed.indexOf("```json") + 7;
			int end = trimmed.indexOf("```", start);
			if (end > start) {
				return trimmed.substring(start, end).trim();
			}
		}
		if (trimmed.contains("```")) {
			int start = trimmed.indexOf("```") + 3;
			// Skip optional language identifier on the same line
			int lineEnd = trimmed.indexOf('\n', start);
			if (lineEnd > start) {
				start = lineEnd + 1;
			}
			int end = trimmed.indexOf("```", start);
			if (end > start) {
				return trimmed.substring(start, end).trim();
			}
		}
		// Try to find raw JSON object
		int braceStart = trimmed.indexOf('{');
		int braceEnd = trimmed.lastIndexOf('}');
		if (braceStart >= 0 && braceEnd > braceStart) {
			return trimmed.substring(braceStart, braceEnd + 1);
		}
		return trimmed;
	}

	private String extractRationale(String fullContent, String jsonPayload) {
		// Everything outside the JSON is rationale
		String without = fullContent.replace(jsonPayload, "").trim();
		// Strip markdown fences
		without = without.replaceAll("```json\\s*", "").replaceAll("```\\s*", "").trim();
		return without.isBlank() ? "AI-generated suggestion" : without.substring(0, Math.min(500, without.length()));
	}

	private boolean tryAcquireRate() {
		long now = System.currentTimeMillis();
		long windowMs = 60_000;
		if (now - windowStart.get() > windowMs) {
			windowStart.set(now);
			windowCount.set(0);
		}
		return windowCount.incrementAndGet() <= MAX_REQUESTS_PER_MINUTE;
	}

	// ── Observability ────────────────────────────────────────────────────

	/** Total tokens consumed across all requests (for metrics). */
	public long getTotalTokensUsed() {
		return totalTokensUsed.get();
	}

	/** Total requests made (for metrics). */
	public long getTotalRequests() {
		return totalRequests.get();
	}
}

package com.weeklycommit.ai.provider;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Component;

/**
 * Development/test stub implementation of {@link AiProvider}.
 *
 * <p>
 * Returns deterministic canned responses for every suggestion type so the rest
 * of the AI pipeline can be tested end-to-end without a real model. Always
 * reports itself as available.
 */
@Component
@org.springframework.boot.autoconfigure.condition.ConditionalOnProperty(name = "ai.provider", havingValue = "stub")
public class StubAiProvider implements AiProvider {

	private static final Logger log = LoggerFactory.getLogger(StubAiProvider.class);

	static final String STUB_MODEL_VERSION = "stub-v1";

	@Override
	public String getName() {
		return "stub";
	}

	@Override
	public String getVersion() {
		return STUB_MODEL_VERSION;
	}

	@Override
	public boolean isAvailable() {
		return true;
	}

	@Override
	public AiSuggestionResult generateSuggestion(AiContext context) {
		log.debug("StubAiProvider.generateSuggestion: type={}", context.suggestionType());
		String payload;
		String rationale;
		double confidence = 0.85;

		switch (context.suggestionType()) {
			case AiContext.TYPE_COMMIT_DRAFT -> {
				payload = """
						{
						  "suggestedTitle": "Implement feature with clear acceptance criteria",
						  "suggestedDescription": "Break this commit into smaller, measurable deliverables.",
						  "suggestedSuccessCriteria": "Feature is deployed and passing all tests.",
						  "suggestedEstimatePoints": 3
						}
						""";
				rationale = "Commit title appears vague; similar past commits used more specific language.";
			}
			case AiContext.TYPE_COMMIT_LINT -> {
				payload = """
						{
						  "hardValidation": [],
						  "softGuidance": [
						    {
						      "code": "VAGUE_TITLE",
						      "message": "Consider making the title more specific and outcome-focused."
						    }
						  ]
						}
						""";
				rationale = "Commit title could be more specific. No hard violations detected.";
				confidence = 0.9;
			}
			case AiContext.TYPE_RCDO_SUGGEST -> {
				Object rcdoList = context.rcdoTree() != null && !context.rcdoTree().isEmpty()
						? context.rcdoTree().get(0).get("id")
						: null;
				payload = String.format("""
						{
						  "suggestedRcdoNodeId": "%s",
						  "confidence": 0.85
						}
						""", rcdoList != null ? rcdoList : "");
				rationale = "Commit title and description closely match this Outcome's scope.";
				confidence = 0.85;
			}
			case AiContext.TYPE_RISK_SIGNAL -> {
				payload = """
						{
						  "signals": []
						}
						""";
				rationale = "No risk signals detected for this plan.";
				confidence = 0.95;
			}
			case AiContext.TYPE_RECONCILE_ASSIST -> {
				payload = """
						{
						  "likelyOutcomes": [],
						  "draftSummary": "Plan reconciliation appears straightforward with no major deviations.",
						  "carryForwardRecommendations": []
						}
						""";
				rationale = "No unresolved commits detected that require carry-forward.";
			}
			case AiContext.TYPE_TEAM_SUMMARY -> {
				payload = """
						{
						  "summaryText": "Team plan looks healthy this week.",
						  "topRcdoBranches": [],
						  "carryForwardPatterns": [],
						  "criticalBlockedItemIds": []
						}
						""";
				rationale = "Generated from team plan data for the requested week.";
			}
			case AiContext.TYPE_RAG_INTENT -> {
				payload = """
						{
						  "intent": "status_query",
						  "userFilter": "team",
						  "entityTypes": ["commit", "plan_summary"],
						  "timeRange": null,
						  "keywords": ["weekly", "commit", "plan"]
						}
						""";
				rationale = "Intent classified as a general status query over commits and plans.";
			}
			case AiContext.TYPE_RAG_QUERY -> {
				payload = """
						{
						  "answer": "Based on the retrieved planning data, the team is making steady progress.",
						  "sources": [],
						  "confidence": 0.85
						}
						""";
				rationale = "Answer generated from retrieved context chunks.";
			}
			case AiContext.TYPE_TEAM_INSIGHT -> {
				payload = """
						{
						  "insights": [
						    {
						      "insightText": "The team shows consistent carry-forward patterns suggesting recurring capacity pressure.",
						      "severity": "MEDIUM",
						      "sourceEntityIds": [],
						      "actionSuggestion": "Review team capacity and consider reducing weekly commitment scope."
						    }
						  ]
						}
						""";
				rationale = "Team insight generated from historical planning patterns.";
			}
			case AiContext.TYPE_PERSONAL_INSIGHT -> {
				payload = """
						{
						  "insights": [
						    {
						      "insightText": "You consistently achieve your high-priority commits. Consider raising the bar on estimates.",
						      "severity": "LOW",
						      "sourceEntityIds": [],
						      "actionSuggestion": "Incrementally increase estimate points on KING/QUEEN commits."
						    }
						  ]
						}
						""";
				rationale = "Personal insight generated from recent plan history.";
			}
			case AiContext.TYPE_WHAT_IF -> {
				payload = """
						{
						  "narrative": "This change would shift the plan's total points and affect RCDO coverage as described.",
						  "recommendation": "Consider whether the capacity change aligns with your weekly goals."
						}
						""";
				rationale = "Stub what-if narration generated for simulation result.";
			}
			default -> {
				payload = "{}";
				rationale = "Unknown suggestion type.";
				confidence = 0.0;
			}
		}

		return new AiSuggestionResult(true, payload.trim(), rationale, confidence, STUB_MODEL_VERSION);
	}
}

package com.weeklycommit.ai.service;

import com.fasterxml.jackson.databind.JsonNode;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.weeklycommit.ai.dto.WhatIfRequest;
import com.weeklycommit.ai.dto.WhatIfRequest.WhatIfMutation;
import com.weeklycommit.ai.dto.WhatIfRequest.WhatIfMutation.WhatIfAction;
import com.weeklycommit.ai.dto.WhatIfResponse;
import com.weeklycommit.ai.dto.WhatIfResponse.PlanSnapshot;
import com.weeklycommit.ai.dto.WhatIfResponse.RcdoCoverageChange;
import com.weeklycommit.ai.dto.WhatIfResponse.RiskDelta;
import com.weeklycommit.ai.provider.AiContext;
import com.weeklycommit.ai.provider.AiProviderRegistry;
import com.weeklycommit.ai.provider.AiSuggestionResult;
import com.weeklycommit.domain.entity.WeeklyCommit;
import com.weeklycommit.domain.entity.WeeklyPlan;
import com.weeklycommit.domain.entity.WorkItem;
import com.weeklycommit.domain.entity.WorkItemStatusHistory;
import com.weeklycommit.domain.enums.ChessPiece;
import com.weeklycommit.domain.enums.TicketStatus;
import com.weeklycommit.domain.repository.ScopeChangeEventRepository;
import com.weeklycommit.domain.repository.WeeklyCommitRepository;
import com.weeklycommit.domain.repository.WeeklyPlanRepository;
import com.weeklycommit.domain.repository.WorkItemRepository;
import com.weeklycommit.domain.repository.WorkItemStatusHistoryRepository;
import com.weeklycommit.rcdo.exception.ResourceNotFoundException;
import java.time.Duration;
import java.time.Instant;
import java.util.ArrayList;
import java.util.HashSet;
import java.util.LinkedHashMap;
import java.util.List;
import java.util.Map;
import java.util.Set;
import java.util.UUID;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

/**
 * What-If simulation service: pure computation + optional LLM narration.
 *
 * <p>
 * Applies hypothetical commit mutations in-memory against a plan's current
 * state and returns a before/after analysis: capacity delta, per-RCDO-node
 * coverage changes, and risk signal diff. No data is persisted.
 *
 * <p>
 * After computing the structured impact the service optionally calls the LLM to
 * produce a 2-3 sentence narrative and a short recommendation. When AI is
 * unavailable the full structured response is still returned with
 * {@code narrative=null} and {@code recommendation=null}.
 *
 * <p>
 * Risk thresholds are duplicated from {@code RiskDetectionService} as
 * package-private constants so that the simulation can run without calling the
 * persistence-backed detection service.
 */
@Service
@Transactional(readOnly = true)
public class WhatIfService {

	private static final Logger log = LoggerFactory.getLogger(WhatIfService.class);

	/** Blocked-for threshold in hours for the BLOCKED_CRITICAL signal. */
	static final long BLOCKED_CRITICAL_HOURS = 48;

	/** Carry-forward streak threshold for the REPEATED_CARRY_FORWARD signal. */
	static final int CARRY_FORWARD_STREAK_THRESHOLD = 2;

	/** Scope-change count threshold for SCOPE_VOLATILITY. */
	static final int SCOPE_VOLATILITY_THRESHOLD = 3;

	/** Minimum fill rate (fraction of capacity) to avoid UNDERCOMMIT. */
	static final double UNDERCOMMIT_THRESHOLD = 0.60;

	private final WeeklyPlanRepository planRepo;
	private final WeeklyCommitRepository commitRepo;
	private final ScopeChangeEventRepository scopeChangeRepo;
	private final WorkItemRepository workItemRepo;
	private final WorkItemStatusHistoryRepository statusHistoryRepo;
	private final AiProviderRegistry aiProviderRegistry;
	private final ObjectMapper objectMapper;

	public WhatIfService(WeeklyPlanRepository planRepo, WeeklyCommitRepository commitRepo,
			ScopeChangeEventRepository scopeChangeRepo, WorkItemRepository workItemRepo,
			WorkItemStatusHistoryRepository statusHistoryRepo, AiProviderRegistry aiProviderRegistry,
			ObjectMapper objectMapper) {
		this.planRepo = planRepo;
		this.commitRepo = commitRepo;
		this.scopeChangeRepo = scopeChangeRepo;
		this.workItemRepo = workItemRepo;
		this.statusHistoryRepo = statusHistoryRepo;
		this.aiProviderRegistry = aiProviderRegistry;
		this.objectMapper = objectMapper;
	}

	// -------------------------------------------------------------------------
	// Public API
	// -------------------------------------------------------------------------

	/**
	 * Simulates the impact of hypothetical mutations on a plan and optionally adds
	 * an LLM narrative.
	 *
	 * @param request
	 *            the what-if request with mutations to apply
	 * @return structured before/after analysis; narrative/recommendation are null
	 *         when AI is unavailable
	 * @throws ResourceNotFoundException
	 *             if the plan does not exist
	 */
	public WhatIfResponse simulate(WhatIfRequest request) {
		WeeklyPlan plan = planRepo.findById(request.planId())
				.orElseThrow(() -> new ResourceNotFoundException("Plan not found: " + request.planId()));

		List<WeeklyCommit> originalCommits = commitRepo.findByPlanIdOrderByPriorityOrder(request.planId());

		// Scope change count is the same for both snapshots (mutations don't add
		// events)
		long scopeChangeCount = scopeChangeRepo.findByPlanIdOrderByCreatedAtAsc(request.planId()).size();

		PlanSnapshot currentState = buildSnapshot(plan, originalCommits, scopeChangeCount);

		List<WeeklyCommit> mutatedCommits = applyMutations(originalCommits, request.hypotheticalChanges(), plan);

		PlanSnapshot projectedState = buildSnapshot(plan, mutatedCommits, scopeChangeCount);

		int capacityDelta = projectedState.totalPoints() - currentState.totalPoints();

		List<RcdoCoverageChange> coverageChanges = computeCoverageChanges(currentState.rcdoCoverage(),
				projectedState.rcdoCoverage());

		RiskDelta riskDelta = computeRiskDelta(currentState.riskSignals(), projectedState.riskSignals());

		// Optional LLM narration — never blocks the structured response
		String[] narration = fetchNarration(request, currentState, projectedState, capacityDelta, riskDelta,
				coverageChanges);

		return new WhatIfResponse(true, currentState, projectedState, capacityDelta, coverageChanges, riskDelta,
				narration[0], narration[1]);
	}

	// -------------------------------------------------------------------------
	// LLM narration
	// -------------------------------------------------------------------------

	/**
	 * Calls the LLM to produce a narrative and recommendation for the impact.
	 * Returns a two-element array: {@code [narrative, recommendation]}, both
	 * possibly null on AI unavailability or parse failure.
	 */
	private String[] fetchNarration(WhatIfRequest request, PlanSnapshot currentState, PlanSnapshot projectedState,
			int capacityDelta, RiskDelta riskDelta, List<RcdoCoverageChange> coverageChanges) {
		if (!aiProviderRegistry.isAiEnabled()) {
			return new String[]{null, null};
		}
		try {
			Map<String, Object> additionalContext = buildNarrationContext(currentState, projectedState, capacityDelta,
					riskDelta, coverageChanges);
			AiContext context = new AiContext(AiContext.TYPE_WHAT_IF, request.userId(), request.planId(), null,
					Map.of(), Map.of(), List.of(), List.of(), additionalContext);
			AiSuggestionResult result = aiProviderRegistry.generateSuggestion(context);
			if (!result.available() || result.payload() == null) {
				return new String[]{null, null};
			}
			return parseNarration(result.payload());
		} catch (Exception e) {
			log.debug("LLM narration failed for what-if plan {}: {}", request.planId(), e.getMessage());
			return new String[]{null, null};
		}
	}

	private String[] parseNarration(String payload) {
		try {
			JsonNode node = objectMapper.readTree(payload);
			String narrative = textOrNull(node, "narrative");
			String recommendation = textOrNull(node, "recommendation");
			return new String[]{narrative, recommendation};
		} catch (Exception e) {
			log.debug("Failed to parse what-if narration payload: {}", e.getMessage());
			return new String[]{null, null};
		}
	}

	private static String textOrNull(JsonNode node, String field) {
		JsonNode child = node.get(field);
		if (child == null || child.isNull()) {
			return null;
		}
		String text = child.asText();
		return (text.isBlank() || "null".equalsIgnoreCase(text)) ? null : text;
	}

	/**
	 * Serialises the computed impact data into the additionalContext map that the
	 * LLM prompt template reads.
	 */
	private Map<String, Object> buildNarrationContext(PlanSnapshot currentState, PlanSnapshot projectedState,
			int capacityDelta, RiskDelta riskDelta, List<RcdoCoverageChange> coverageChanges) {
		Map<String, Object> ctx = new LinkedHashMap<>();
		ctx.put("currentTotalPoints", currentState.totalPoints());
		ctx.put("projectedTotalPoints", projectedState.totalPoints());
		ctx.put("capacityBudget", currentState.capacityBudget());
		ctx.put("capacityDelta", capacityDelta);
		ctx.put("currentRiskSignals", currentState.riskSignals());
		ctx.put("projectedRiskSignals", projectedState.riskSignals());
		ctx.put("newRisks", riskDelta.newRisks());
		ctx.put("resolvedRisks", riskDelta.resolvedRisks());

		List<Map<String, Object>> coverageList = new ArrayList<>();
		for (RcdoCoverageChange change : coverageChanges) {
			Map<String, Object> cc = new LinkedHashMap<>();
			cc.put("rcdoNodeId", change.rcdoNodeId() != null ? change.rcdoNodeId().toString() : null);
			cc.put("beforePoints", change.beforePoints());
			cc.put("afterPoints", change.afterPoints());
			coverageList.add(cc);
		}
		ctx.put("rcdoCoverageChanges", coverageList);
		return ctx;
	}

	// -------------------------------------------------------------------------
	// Snapshot building
	// -------------------------------------------------------------------------

	private PlanSnapshot buildSnapshot(WeeklyPlan plan, List<WeeklyCommit> commits, long scopeChangeCount) {
		int totalPoints = commits.stream().mapToInt(c -> c.getEstimatePoints() != null ? c.getEstimatePoints() : 0)
				.sum();
		int budget = plan.getCapacityBudgetPoints();
		List<String> signals = detectSignals(commits, scopeChangeCount, totalPoints, budget);
		Map<UUID, Integer> rcdoCoverage = computeRcdoCoverage(commits);
		return new PlanSnapshot(totalPoints, budget, signals, rcdoCoverage);
	}

	/**
	 * Replicates the 5 risk rules from {@code RiskDetectionService} inline, without
	 * persisting any signals.
	 */
	private List<String> detectSignals(List<WeeklyCommit> commits, long scopeChangeCount, int totalPoints, int budget) {
		List<String> signals = new ArrayList<>();

		// 1. OVERCOMMIT
		if (totalPoints > budget) {
			signals.add("OVERCOMMIT");
		}

		// 2. UNDERCOMMIT
		if (budget > 0 && (double) totalPoints / budget < UNDERCOMMIT_THRESHOLD) {
			signals.add("UNDERCOMMIT");
		}

		// 3. REPEATED_CARRY_FORWARD
		for (WeeklyCommit commit : commits) {
			if (commit.getCarryForwardStreak() >= CARRY_FORWARD_STREAK_THRESHOLD) {
				signals.add("REPEATED_CARRY_FORWARD");
				break;
			}
		}

		// 4. BLOCKED_CRITICAL
		Instant now = Instant.now();
		outer : for (WeeklyCommit commit : commits) {
			if (commit.getChessPiece() != ChessPiece.KING && commit.getChessPiece() != ChessPiece.QUEEN) {
				continue;
			}
			if (commit.getWorkItemId() == null) {
				continue;
			}
			WorkItem ticket = workItemRepo.findById(commit.getWorkItemId()).orElse(null);
			if (ticket == null || ticket.getStatus() != TicketStatus.BLOCKED) {
				continue;
			}
			Instant blockedSince = findBlockedSince(ticket.getId());
			if (blockedSince != null && Duration.between(blockedSince, now).toHours() >= BLOCKED_CRITICAL_HOURS) {
				signals.add("BLOCKED_CRITICAL");
				break outer;
			}
		}

		// 5. SCOPE_VOLATILITY
		if (scopeChangeCount > SCOPE_VOLATILITY_THRESHOLD) {
			signals.add("SCOPE_VOLATILITY");
		}

		return signals;
	}

	private Map<UUID, Integer> computeRcdoCoverage(List<WeeklyCommit> commits) {
		Map<UUID, Integer> coverage = new LinkedHashMap<>();
		for (WeeklyCommit commit : commits) {
			if (commit.getRcdoNodeId() == null) {
				continue;
			}
			int points = commit.getEstimatePoints() != null ? commit.getEstimatePoints() : 0;
			coverage.merge(commit.getRcdoNodeId(), points, Integer::sum);
		}
		return coverage;
	}

	private Instant findBlockedSince(UUID workItemId) {
		List<WorkItemStatusHistory> history = statusHistoryRepo.findByWorkItemIdOrderByCreatedAtAsc(workItemId);
		for (int i = history.size() - 1; i >= 0; i--) {
			if ("BLOCKED".equals(history.get(i).getToStatus())) {
				return history.get(i).getCreatedAt();
			}
		}
		return null;
	}

	// -------------------------------------------------------------------------
	// Mutation application
	// -------------------------------------------------------------------------

	private List<WeeklyCommit> applyMutations(List<WeeklyCommit> originalCommits, List<WhatIfMutation> mutations,
			WeeklyPlan plan) {
		List<WeeklyCommit> commits = new ArrayList<>(originalCommits.stream().map(this::copyCommit).toList());

		if (mutations == null || mutations.isEmpty()) {
			return commits;
		}

		for (WhatIfMutation mutation : mutations) {
			if (mutation.action() == WhatIfAction.ADD_COMMIT) {
				WeeklyCommit synthetic = new WeeklyCommit();
				synthetic.setId(UUID.randomUUID());
				synthetic.setPlanId(plan.getId());
				synthetic.setOwnerUserId(plan.getOwnerUserId());
				synthetic.setTitle(mutation.title() != null ? mutation.title() : "(hypothetical)");
				synthetic.setChessPiece(parseChessPiece(mutation.chessPiece()));
				synthetic.setEstimatePoints(mutation.estimatePoints());
				synthetic.setRcdoNodeId(mutation.rcdoNodeId());
				synthetic.setPriorityOrder(commits.size() + 1);
				commits.add(synthetic);

			} else if (mutation.action() == WhatIfAction.REMOVE_COMMIT) {
				if (mutation.commitId() != null) {
					commits.removeIf(c -> mutation.commitId().equals(c.getId()));
				}

			} else if (mutation.action() == WhatIfAction.MODIFY_COMMIT) {
				if (mutation.commitId() != null) {
					for (WeeklyCommit c : commits) {
						if (mutation.commitId().equals(c.getId())) {
							if (mutation.title() != null) {
								c.setTitle(mutation.title());
							}
							if (mutation.chessPiece() != null) {
								c.setChessPiece(parseChessPiece(mutation.chessPiece()));
							}
							if (mutation.estimatePoints() != null) {
								c.setEstimatePoints(mutation.estimatePoints());
							}
							if (mutation.rcdoNodeId() != null) {
								c.setRcdoNodeId(mutation.rcdoNodeId());
							}
							break;
						}
					}
				}
			}
		}

		return commits;
	}

	private WeeklyCommit copyCommit(WeeklyCommit original) {
		WeeklyCommit copy = new WeeklyCommit();
		copy.setId(original.getId());
		copy.setPlanId(original.getPlanId());
		copy.setOwnerUserId(original.getOwnerUserId());
		copy.setTitle(original.getTitle());
		copy.setDescription(original.getDescription());
		copy.setChessPiece(original.getChessPiece());
		copy.setPriorityOrder(original.getPriorityOrder());
		copy.setRcdoNodeId(original.getRcdoNodeId());
		copy.setWorkItemId(original.getWorkItemId());
		copy.setEstimatePoints(original.getEstimatePoints());
		copy.setSuccessCriteria(original.getSuccessCriteria());
		copy.setOutcome(original.getOutcome());
		copy.setCarryForwardStreak(original.getCarryForwardStreak());
		copy.setCarryForwardSourceId(original.getCarryForwardSourceId());
		return copy;
	}

	private ChessPiece parseChessPiece(String chessPiece) {
		if (chessPiece == null || chessPiece.isBlank()) {
			return null;
		}
		try {
			return ChessPiece.valueOf(chessPiece.toUpperCase());
		} catch (IllegalArgumentException e) {
			return null;
		}
	}

	// -------------------------------------------------------------------------
	// Delta computation
	// -------------------------------------------------------------------------

	private List<RcdoCoverageChange> computeCoverageChanges(Map<UUID, Integer> before, Map<UUID, Integer> after) {
		List<RcdoCoverageChange> changes = new ArrayList<>();
		Set<UUID> allNodes = new HashSet<>();
		allNodes.addAll(before.keySet());
		allNodes.addAll(after.keySet());

		for (UUID nodeId : allNodes) {
			int beforePts = before.getOrDefault(nodeId, 0);
			int afterPts = after.getOrDefault(nodeId, 0);
			if (beforePts != afterPts) {
				changes.add(new RcdoCoverageChange(nodeId, null, beforePts, afterPts));
			}
		}
		return changes;
	}

	private RiskDelta computeRiskDelta(List<String> current, List<String> projected) {
		Set<String> currentSet = new HashSet<>(current);
		Set<String> projectedSet = new HashSet<>(projected);

		List<String> newRisks = projected.stream().filter(s -> !currentSet.contains(s)).toList();
		List<String> resolvedRisks = current.stream().filter(s -> !projectedSet.contains(s)).toList();

		return new RiskDelta(newRisks, resolvedRisks);
	}
}

